import { IDanfe, IDanfeProduct } from '../types/types';

const XML_ENTITY_REGEX = /&(#\d+|#x[\da-fA-F]+|[a-zA-Z]+);/g;
const XML_ENTITY_FALLBACK_MAP: Record<string, string> = {
  amp: '&',
  apos: '\'',
  quot: '"',
  lt: '<',
  gt: '>',
  nbsp: ' ',
};

let xmlEntityDecoder: HTMLTextAreaElement | null = null;

function decodeXmlEntitiesOnce(input: string) {
  if (typeof document !== 'undefined') {
    if (!xmlEntityDecoder) {
      xmlEntityDecoder = document.createElement('textarea');
    }
    xmlEntityDecoder.innerHTML = input;
    return xmlEntityDecoder.value;
  }

  return input.replace(XML_ENTITY_REGEX, (fullMatch, entityRaw) => {
    const entity = String(entityRaw || '').trim();
    if (!entity) return fullMatch;

    if (entity.startsWith('#x') || entity.startsWith('#X')) {
      const codePoint = Number.parseInt(entity.slice(2), 16);
      return Number.isFinite(codePoint) ? String.fromCharCode(codePoint) : fullMatch;
    }

    if (entity.startsWith('#')) {
      const codePoint = Number.parseInt(entity.slice(1), 10);
      return Number.isFinite(codePoint) ? String.fromCharCode(codePoint) : fullMatch;
    }

    const fallback = XML_ENTITY_FALLBACK_MAP[entity.toLowerCase()];
    return fallback ?? fullMatch;
  });
}

export function decodeXmlEntitiesDeep(value: unknown, maxDepth = 4) {
  let current = String(value || '');
  for (let depth = 0; depth < maxDepth; depth += 1) {
    const decoded = decodeXmlEntitiesOnce(current);
    if (decoded === current) break;
    current = decoded;
  }
  return current;
}

export function normalizeTextValue(value: unknown) {
  return decodeXmlEntitiesDeep(String(value || '').trim());
}

export function normalizeCityLabel(value: unknown) {
  return normalizeTextValue(value);
}

function toNullableText(value: unknown) {
  const normalized = normalizeTextValue(value);
  return normalized || null;
}

export function sanitizeDanfeProduct(product: IDanfeProduct): IDanfeProduct {
  const fallbackCode = normalizeTextValue(product.Product?.code || product.product_id);
  const fallbackType = normalizeTextValue(product.Product?.type || product.type);
  const fallbackDescription = normalizeTextValue(product.Product?.description) || 'Produto sem descricao';
  const fallbackPrice = normalizeTextValue(product.Product?.price || product.price) || '0';

  return {
    ...product,
    product_id: normalizeTextValue(product.product_id) || fallbackCode || undefined,
    type: normalizeTextValue(product.type || fallbackType),
    Product: {
      code: fallbackCode,
      description: fallbackDescription,
      price: fallbackPrice,
      type: fallbackType,
    },
  };
}

export function sanitizeDanfeTextFields(danfe: IDanfe): IDanfe {
  return {
    ...danfe,
    representative_name: toNullableText(danfe.representative_name),
    replacement_invoice_number: toNullableText(danfe.replacement_invoice_number),
    replacement_reason: toNullableText(danfe.replacement_reason),
    replacement_invoice: danfe.replacement_invoice
      ? {
        invoice_number: toNullableText(danfe.replacement_invoice.invoice_number),
        status: toNullableText(danfe.replacement_invoice.status),
        invoice_date: toNullableText(danfe.replacement_invoice.invoice_date),
      }
      : null,
    replaced_invoice_number: toNullableText(danfe.replaced_invoice_number),
    replaced_invoice: danfe.replaced_invoice
      ? {
        invoice_number: toNullableText(danfe.replaced_invoice.invoice_number),
        status: toNullableText(danfe.replaced_invoice.status),
        invoice_date: toNullableText(danfe.replaced_invoice.invoice_date),
      }
      : null,
    Customer: {
      ...danfe.Customer,
      name_or_legal_entity: normalizeTextValue(danfe.Customer?.name_or_legal_entity),
      city: normalizeCityLabel(danfe.Customer?.city) || '',
      phone: toNullableText(danfe.Customer?.phone),
      address: toNullableText(danfe.Customer?.address),
      address_number: toNullableText(danfe.Customer?.address_number),
      neighborhood: toNullableText(danfe.Customer?.neighborhood),
      state: toNullableText(danfe.Customer?.state),
      zip_code: toNullableText(danfe.Customer?.zip_code),
      cnpj_or_cpf: normalizeTextValue(danfe.Customer?.cnpj_or_cpf),
      representative_name: toNullableText(danfe.Customer?.representative_name),
    },
    DanfeProducts: Array.isArray(danfe.DanfeProducts)
      ? danfe.DanfeProducts.map((product) => sanitizeDanfeProduct(product))
      : danfe.DanfeProducts,
  };
}
